#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume the newline after T
    char buf[256];
    const char *line1 = "A structure is a collection of variables of different data types that are stored together in memory.";
    const char *line2 = "A union is a special type of structure where all the members share the same memory space.";
    for (int i = 0; i < T; ++i) {
        fgets(buf, sizeof(buf), stdin); // read and ignore the question line
        printf("%s\n", line1);
        printf("%s\n", line2);
    }
    return 0;
}

